class SecurePaymentStorage {
  static const String _storageKey = 'payment_transactions';
  static const String _tokenKey = 'payment_tokens';

  Future<void> saveTransaction(PaymentTransaction transaction) async {
    final prefs = await SharedPreferences.getInstance();
    final transactions = await getTransactions();
    transactions.add(transaction);
    final encrypted = _encryptData(
      jsonEncode(transactions.map((e) => e.toJson()).toList()),
    );
    await prefs.setString(_storageKey, encrypted);
  }

  Future<List<PaymentTransaction>> getTransactions() async {
    final prefs = await SharedPreferences.getInstance();
    final encrypted = prefs.getString(_storageKey);
    if (encrypted == null) return [];

    try {
      final decrypted = _decryptData(encrypted);
      final List<dynamic> jsonList = jsonDecode(decrypted);
      return jsonList.map((e) => PaymentTransaction.fromJson(e)).toList();
    } catch (e) {
      return [];
    }
  }

  Future<void> savePaymentToken(String token) async {
    final prefs = await SharedPreferences.getInstance();
    final encrypted = _encryptData(token);
    await prefs.setString(_tokenKey, encrypted);
  }

  Future<String?> getPaymentToken() async {
    final prefs = await SharedPreferences.getInstance();
    final encrypted = prefs.getString(_tokenKey);
    if (encrypted == null) return null;
    return _decryptData(encrypted);
  }

  String _encryptData(String data) {
    final key = utf8.encode('payment_encryption_key_32bytes');
    final bytes = utf8.encode(data);
    final hmac = Hmac(sha256, key);
    final digest = hmac.convert(bytes);
    return base64Encode(bytes) + '.' + digest.toString();
  }

  String _decryptData(String encrypted) {
    final parts = encrypted.split('.');
    if (parts.length != 2) throw Exception('Invalid encrypted data');
    return utf8.decode(base64Decode(parts[0]));
  }

  Future<void> clearAll() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove(_storageKey);
    await prefs.remove(_tokenKey);
  }
}

class StripePaymentGateway {
  final PaymentConfig config;
  final String baseUrl = 'https://api.stripe.com/v1';

  StripePaymentGateway(this.config);

  Future<PaymentResult> createPaymentIntent({
    required double amount,
    required String currency,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$baseUrl/payment_intents'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'amount': (amount * 100).toInt().toString(),
          'currency': currency.toLowerCase(),
          'metadata': jsonEncode(metadata ?? {}),
        },
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return PaymentResult(
          success: true,
          transactionId: data['id'],
          metadata: data,
        );
      } else {
        return PaymentResult(
          success: false,
          message: 'Failed to create payment intent: ${response.body}',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'Error: $e',
      );
    }
  }

  Future<PaymentResult> confirmPayment({
    required String paymentIntentId,
    required String paymentMethodId,
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$baseUrl/payment_intents/$paymentIntentId/confirm'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'payment_method': paymentMethodId,
        },
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return PaymentResult(
          success: data['status'] == 'succeeded',
          transactionId: data['id'],
          metadata: data,
        );
      } else {
        return PaymentResult(
          success: false,
          message: 'Failed to confirm payment: ${response.body}',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'Error: $e',
      );
    }
  }

  Future<PaymentResult> refundPayment({
    required String paymentIntentId,
    double? amount,
  }) async {
    try {
      final body = <String, String>{'payment_intent': paymentIntentId};
      if (amount != null) {
        body['amount'] = (amount * 100).toInt().toString();
      }

      final response = await http.post(
        Uri.parse('$baseUrl/refunds'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: body,
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return PaymentResult(
          success: true,
          transactionId: data['id'],
          metadata: data,
        );
      } else {
        return PaymentResult(
          success: false,
          message: 'Failed to refund payment: ${response.body}',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'Error: $e',
      );
    }
  }
}

