class PaymentValidator {
  static bool validateCreditCard(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    return _luhnCheck(cleaned);
  }

  static bool _luhnCheck(String cardNumber) {
    int sum = 0;
    bool alternate = false;

    for (int i = cardNumber.length - 1; i >= 0; i--) {
      int digit = int.parse(cardNumber[i]);

      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }

      sum += digit;
      alternate = !alternate;
    }

    return sum % 10 == 0;
  }

  static bool validateCVV(String cvv) {
    return RegExp(r'^\d{3,4}$').hasMatch(cvv);
  }

  static bool validateExpiryDate(String expiryDate) {
    final parts = expiryDate.split('/');
    if (parts.length != 2) return false;

    final month = int.tryParse(parts[0]);
    final year = int.tryParse(parts[1]);

    if (month == null || year == null) return false;
    if (month < 1 || month > 12) return false;

    final now = DateTime.now();
    final fullYear = year < 100 ? 2000 + year : year;
    final expiryDateTime = DateTime(fullYear, month);

    return expiryDateTime.isAfter(now);
  }

  static bool validateAmount(double amount) {
    return amount > 0 && amount < 999999.99;
  }
}

class PaymentProcessingModule {
  final PaymentConfig config;
  late final StripePaymentGateway _stripeGateway;
  late final InAppPurchaseManager _inAppPurchaseManager;
  late final ApplePayManager _applePayManager;
  late final GooglePayManager _googlePayManager;
  late final SecurePaymentStorage _storage;

  bool _initialized = false;

  PaymentProcessingModule(this.config) {
    _stripeGateway = StripePaymentGateway(config);
    _inAppPurchaseManager = InAppPurchaseManager();
    _applePayManager = ApplePayManager();
    _googlePayManager = GooglePayManager();
    _storage = SecurePaymentStorage();
  }

  Future<void> initialize() async {
    if (_initialized) return;

    try {
      await _inAppPurchaseManager.initialize();
      _initialized = true;
    } catch (e) {
      throw Exception('Failed to initialize payment module: $e');
    }
  }

  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    String? paymentMethodId,
    String? productId,
    Map<String, dynamic>? metadata,
  }) async {
    if (!_initialized) {
      throw Exception('Payment module not initialized');
    }

    if (!PaymentValidator.validateAmount(amount)) {
      return PaymentResult(
        success: false,
        message: 'Invalid amount',
      );
    }

    PaymentResult result;

    try {
      switch (method) {
        case PaymentMethod.creditCard:
          if (paymentMethodId == null) {
            return PaymentResult(
              success: false,
              message: 'Payment method ID required for credit card payments',
            );
          }
          result = await _processCreditCardPayment(
            amount: amount,
            currency: currency,
            paymentMethodId: paymentMethodId,
            metadata: metadata,
          );
          break;

        case PaymentMethod.applePay:
          result = await _applePayManager.processPayment(
            amount: amount,
            currency: currency,
            merchantId: config.applePayMerchantId,
            countryCode: 'US',
            metadata: metadata,
          );
          break;

        case PaymentMethod.googlePay:
          result = await _googlePayManager.processPayment(
            amount: amount,
            currency: currency,
            merchantId: config.googlePayMerchantId,
            countryCode: 'US',
            metadata: metadata,
          );
          break;

        case PaymentMethod.inAppPurchase:
          if (productId == null) {
            return PaymentResult(
              success: false,
              message: 'Product ID required for in-app purchases',
            );
          }
          result = await _processInAppPurchase(productId);
          break;
      }

      if (result.success && result.transactionId != null) {
        await _saveTransaction(
          transactionId: result.transactionId!,
          amount: amount,
          currency: currency,
          method: method,
          status: PaymentStatus.completed,
          metadata: metadata,
        );
      }

      return result;
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'Payment processing failed: $e',
      );
    }
  }

  Future<PaymentResult> _processCreditCardPayment({
    required double amount,
    required String currency,
    required String paymentMethodId,
    Map<String, dynamic>? metadata,
  }) async {
    final intentResult = await _stripeGateway.createPaymentIntent(
      amount: amount,
      currency: currency,
      metadata: metadata,
    );

    if (!intentResult.success || intentResult.transactionId == null) {
      return intentResult;
    }

    return await _stripeGateway.confirmPayment(
      paymentIntentId: intentResult.transactionId!,
      paymentMethodId: paymentMethodId,
    );
  }

  Future<PaymentResult> _processInAppPurchase(String productId) async {
    final products = await _inAppPurchaseManager.getProducts({productId});

    if (products.isEmpty) {
      return PaymentResult(
        success: false,
        message: 'Product not found',
      );
    }

    return await _inAppPurchaseManager.buyProduct(products.first);
  }

  Future<void> _saveTransaction({
    required String transactionId,
    required double amount,
    required String currency,
    required PaymentMethod method,
    required PaymentStatus status,
    Map<String, dynamic>? metadata,
  }) async {
    final transaction = PaymentTransaction(
      id: transactionId,
      amount: amount,
      currency: currency,
      method: method,
      status: status,
      timestamp: DateTime.now(),
      metadata: metadata,
    );

    await _storage.saveTransaction(transaction);
  }

  Future<List<PaymentTransaction>> getTransactionHistory() async {
    return await _storage.getTransactions();
  }

  Future<PaymentResult> refundTransaction(String transactionId,
      {double? amount}) async {
    return await _stripeGateway.refundPayment(
      paymentIntentId: transactionId,
      amount: amount,
    );
  }

  Future<void> restorePurchases() async {
    await _inAppPurchaseManager.restorePurchases();
  }

  Future<bool> canMakeApplePayPayments() async {
    return await _applePayManager.canMakePayments();
  }

  Future<bool> canMakeGooglePayPayments() async {
    return await _googlePayManager.canMakePayments();
  }

  Stream<PurchaseDetails> get purchaseStream =>
      _inAppPurchaseManager.purchaseStream;

  void dispose() {
    _inAppPurchaseManager.dispose();
  }
}

class PaymentReceipt {
  final String transactionId;
  final double amount;
  final String currency;
  final DateTime timestamp;
  final PaymentMethod method;
  final Map<String, dynamic>? metadata;

  PaymentReceipt({
    required this.transactionId,
    required this.amount,
    required this.currency,
    required this.timestamp,
    required this.method,
    this.metadata,
  });

  String generateReceiptText() {
    final buffer = StringBuffer();
    buffer.writeln('PAYMENT RECEIPT');
    buffer.writeln('=' * 40);
    buffer.writeln('Transaction ID: $transactionId');
    buffer.writeln('Amount: $currency ${amount.toStringAsFixed(2)}');
    buffer.writeln('Payment Method: ${method.toString().split('.').last}');
    buffer.writeln('Date: ${timestamp.toLocal()}');
    if (metadata != null) {
      buffer.writeln('\nMetadata:');
      metadata!.forEach((key, value) {
        buffer.writeln('  $key: $value');
      });
    }
    buffer.writeln('=' * 40);
    return buffer.toString();
  }

  Map<String, dynamic> toJson() => {
        'transactionId': transactionId,
        'amount': amount,
        'currency': currency,
        'timestamp': timestamp.toIso8601String(),
        'method': method.toString(),
        'metadata': metadata,
      };
}

class PaymentLogger {
  final bool enableLogging;

  PaymentLogger({this.enableLogging = false});

  void log(String message, {String? level = 'INFO'}) {
    if (!enableLogging) return;
    final timestamp = DateTime.now().toIso8601String();
    if (kDebugMode) {
      print('[$timestamp] [$level] $message');
    }
  }

  void logTransaction(PaymentTransaction transaction) {
    log('Transaction: ${transaction.id}, Amount: ${transaction.amount} ${transaction.currency}, Status: ${transaction.status}');
  }

  void logError(String message, dynamic error) {
    log('Error: $message - $error', level: 'ERROR');
  }
}

class PaymentSecurity {
  static String sanitizeCardNumber(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 4) return '****';
    return '*' * (cleaned.length - 4) + cleaned.substring(cleaned.length - 4);
  }

  static String hashData(String data) {
    final bytes = utf8.encode(data);
    final digest = sha256.convert(bytes);
    return digest.toString();
  }

  static bool verifyWebhookSignature(
    String payload,
    String signature,
    String secret,
  ) {
    final key = utf8.encode(secret);
    final bytes = utf8.encode(payload);
    final hmac = Hmac(sha256, key);
    final digest = hmac.convert(bytes);
    return digest.toString() == signature;
  }
}